# ============================================================
# Comms
# ============================================================

class Comms:
    @staticmethod
    def handle_simple1(symV, symH, symR, tix, tiy):
        Symmetry.and_sym(symV, symH, symR)
        if tix != 63:
            pass


    SIMPLE1 = 0

    @staticmethod
    def pack_simple1(symV, symH, symR, tix, tiy):
        return (0 << 31) | ((symV & 1) << 30) | ((symH & 1) << 29) | ((symR & 1) << 28) | ((tix & 63) << 22) | ((tiy & 63) << 16)

    @staticmethod
    def unpack_simple1(val):
        return (((val >> 30) & 1), ((val >> 29) & 1), ((val >> 28) & 1), ((val >> 22) & 63), ((val >> 16) & 63))

    @staticmethod
    def handle_message(val):
        t = val >> 31

        if t == 0:
            Comms.handle_simple1(((val >> 30) & 1), ((val >> 29) & 1), ((val >> 28) & 1), ((val >> 22) & 63), ((val >> 16) & 63))
            return

        assert False


# ============================================================
# ConnectManager
# ============================================================

class ConnectManager:
    @classmethod
    def get_connect_target_info(cls) -> TransporterInfo | None:
        roots = VisionTracker.disconnected_roots
        if not roots:
            return None

        best: TransporterInfo = roots[0]
        for cand in roots[1:]:
            if TransporterInfo.is_better_connect_than(cand, best):
                best = cand

        if best.bfs_dist_target_adj >= 20:
            return None
        if not best.easily_buildable:
            return None
        if not VisionTracker.me_is_canonical_ally(best.target):
            return None

        return best


