# ============================================================
# CoreHistory
# ============================================================

class CoreHistory:

    wround: int
    hp_hist = [500] * 100

    @classmethod
    def fill(cls):
        cls.wround = Globals.round % 100
        cls.hp_hist[cls.wround] = Globals.ct.get_hp()

    @classmethod
    def hp_delta(cls, rounds: int):  
        # negative when HP lost
        assert rounds < 100
        return cls.hp_hist[cls.wround] - cls.hp_hist[(cls.wround - rounds) % 100]


# ============================================================
# DarkForest
# ============================================================

class DarkForest:
    nodes: list[TreeNode | None] = [None] * 3136
    kind: list[int] = [0] * 3136   # per-position sink class
    flow: list[int]        # flow in subtree (bottom-up)
    pressure: list[int]    # pressure at node (top-down, reset at sink boundaries)
    node_kind: list[int]   # propagated kind per node (top-down)
    core_sink_set: set[int] = set()  # titanium-only ALLY_CORE reachable nodes below pressure threshold
    sink_set: set[int]               # alias for core_sink_set (backward compat)
    leaf_set: set[int]               # titanium leaf nodes — valid foundry sites
    ax_tagged: list[bool]            # True if node has any axionite flow in subtree
    sight_last_id: list[int]         # last resource-ID seen at this position; -1 = never
    sight_last_round: list[int]      # game-round when that ID was last observed
    sight_flowing: list[bool]        # sight-based flow: True if fresh valid resource seen recently
    foundry_positions: set[int] = set()  # persistent: encoded positions of built foundries
    refined_ax_line: set[int] = set()    # recomputed each tick: ALLY_CORE nodes on refined-axionite output paths

    @classmethod
    def init(cls):

        cls.sight_last_id    = [-1]                      * 3136
        cls.sight_last_round = [-4 - 1] * 3136

        if Globals.my_type == EntityType.BUILDER_BOT:
            for p in Unit.core_pos_set:
                cls.register_sink(p, 1)
            return

        if Globals.my_type in (EntityType.SENTINEL, EntityType.GUNNER):
            cls.register_sink((((Globals.my_pos.x) + 3) * 56 + ((Globals.my_pos.y) + 3)),
                              3)

    @classmethod
    def compute_core_sink_set(cls):
        """No-op: core_sink_set is now computed directly in fcompute."""
        pass

    @classmethod
    def register_enemy_core(cls):
        for p in Symmetry.enemy_core_pos_set:
            cls.register_sink(p, 2)

    @classmethod
    def remove_node(cls, u: int):
        if cls.kind[u] == 1 or cls.kind[u] == 2:
            return
        cls.nodes[u] = None
        cls.kind[u] = 0

    @classmethod
    def register_sink(cls, u: int, k: int):
        """Mark position u as a sink of class k and ensure a root node exists there."""
        cls.kind[u] = k
        ns = cls.nodes
        if ns[u] is None:
            n = TreeNode()
            n.up = None
            ns[u] = n
        else:
            ns[u].up = None  # sinks are roots

    @classmethod
    def add_edge(cls, u: int, v: int):
        # register (u,v) edge: u.up = v
        ns = cls.nodes
        if ns[u] is None:
            ns[u] = TreeNode()
        ns[u].up = v



    @classmethod
    def debug_pressure(cls):
        """Draw dots: green=low, yellow=med, orange=high, red=saturated."""
        ns = cls.nodes
        pressure = cls.pressure
        ct = Globals.ct
        for x in range(50):
            for y in range(50):
                i = (((x) + 3) * 56 + ((y) + 3))
                if ns[i] is not None and pressure[i] > 0:
                    p = pressure[i]
                    if p <= 12:
                        ct.draw_indicator_dot(Position(x, y), 0, 255, 0)
                    elif p <= 24:
                        ct.draw_indicator_dot(Position(x, y), 255, 255, 0)
                    elif p <= 36:
                        ct.draw_indicator_dot(Position(x, y), 255, 128, 0)
                    else:
                        ct.draw_indicator_dot(Position(x, y), 255, 0, 0)


