                if ti.entity_type == EntityType.HARVESTER:
                    nidx = idx -1
                    if DarkForest.node_kind[nidx] in (1, 3):
                        info.is_harvester_feeding_ally = True
                    nidx = idx +1
                    if DarkForest.node_kind[nidx] in (1, 3):
                        info.is_harvester_feeding_ally = True
