# OreExecutive
# ============================================================

class OreExecutive:
    state: dict[Position, int] = defaultdict(int)
    ti_queue: list[tuple[int, Position]] = []
    ax_queue: list[tuple[int, Position]] = []
    # nearby_ti_queue removed (reverted c187f820)

    hard_building_set: set[EntityType] = {EntityType.HARVESTER, EntityType.FOUNDRY, EntityType.SENTINEL}

    @classmethod
    def fill(cls):
        for pos, x, y, idx, ti in Map.proc_nearby_tiles:
            # not using Map.harvester_set..?
            
            if ti.entity_type == EntityType.FOUNDRY:
                if idx not in RouteToFoundry.planned_foundry_positions:
                    FoundryBuild.register_foundry(pos)
                continue

            if cls.state[pos] == 2:
                continue
            env = ti.env

            if ti.entity_type in cls.hard_building_set:
                continue


            if ti.has_building and not ti.is_building_ally:
                continue


            if env == Environment.ORE_TITANIUM or env == Environment.ORE_AXIONITE:



                if env == Environment.ORE_TITANIUM:
                    if cls.state[pos] != 1:  # intended: can potentially requeue
                        heapq.heappush(cls.ti_queue, (int(5 * math.sqrt(pos.distance_squared(Unit.core_pos)) + BfsBureau.bfs20_dist[idx]), pos))
                        cls.state[pos] = 1

                if env == Environment.ORE_AXIONITE:
                    if cls.state[pos] != 4:  # intended: can potentially requeue
                        heapq.heappush(cls.ax_queue, (int(5 * math.sqrt(pos.distance_squared(Unit.core_pos)) + BfsBureau.bfs20_dist[idx]), pos))
                        cls.state[pos] = 4


    @classmethod
    def get_titanium_target(cls) -> Position | None:
        ret = None
        while cls.ti_queue:
            dist, pos = cls.ti_queue[0]

            if cls.state[pos] == 2:
                heapq.heappop(cls.ti_queue)
                continue

            ti = Map.tile_info[pos.x][pos.y]

            if ti.entity_type in cls.hard_building_set:
                heapq.heappop(cls.ti_queue)
                cls.state[pos] = 3
                continue
            if ti.entity_type == EntityType.FOUNDRY:
                heapq.heappop(cls.ti_queue)
                cls.state[pos] = 3  # just to prevent requeuing, doesn't matter much
                continue

            if ti.has_building and not ti.is_building_ally:
                heapq.heappop(cls.ti_queue)
                cls.state[pos] = 3
                continue

            if not ti.has_bot and MarketMaker.should_build_harvester(pos):  # fixed: was should_build_ax_harvester
                ret = pos
                break
            else:
                break

        if ret is None:
            return None

        if not VisionTracker.me_is_canonical_ally(ret):
            # just kill?
            return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 0][ret.y + -1]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 1][ret.y + 0]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 0][ret.y + 1]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + -1][ret.y + 0]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        return ret

    @classmethod
    def get_axionite_target(cls) -> Position | None:
        if Globals.round < Constants.AXIONITE_START:
            return None  # don't want to waste resources on axionite early on

        ret = None
        while cls.ax_queue:
            dist, pos = cls.ax_queue[0]

            if cls.state[pos] == 2:
                heapq.heappop(cls.ax_queue)
                continue

            ti = Map.tile_info[pos.x][pos.y]

            if ti.entity_type in cls.hard_building_set:
                heapq.heappop(cls.ax_queue)
                cls.state[pos] = 3
                continue

            if ti.has_building and not ti.is_building_ally:
                heapq.heappop(cls.ax_queue)
                cls.state[pos] = 3
                continue

            if not ti.has_bot and MarketMaker.should_build_harvester(pos):
                ret = pos
                break
            else:
                break

        if ret is None:
            return None

        if not VisionTracker.me_is_canonical_ally(ret):
            # just kill?
            cls.state[ret] = 2
            return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 0][ret.y + -1]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 1][ret.y + 0]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + 0][ret.y + 1]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        # Don't build harvesters next to enemy buildings (because they can destroy them and build a turret)
        ti: TileInfo = Map.tile_info[ret.x + -1][ret.y + 0]
        if ti is not None:
            if ti.has_turret and not ti.is_building_ally:
                cls.state[ret] = 2
                return None


        return ret


    @classmethod
    def go_build_harvester(cls, pos, isAttack = False):
        Pathfinder.move_to(pos, ban_target_pos=True, orbit=(not BuildManager.can_afford_harvester()))

        if Pathfinder.given_up:
            Debug.line(pos, Color.RED)
            Debug.diamond(Color.RED)
            cls.state[pos] = 2
            return

        if BuildManager.can_dbuild_harvester(pos):
            Debug.line(pos, Color.YELLOW)
            BuildManager.dbuild_harvester(pos)

            cand: OrePositionPicker.Candidate = OrePositionPicker.pick_best_candidate(pos)
            if cand is not None:
                RouteToCore.set_pos(cand.position)
                RouteToCore.isAttack = isAttack

    @classmethod
    def go_build_ax_harvester(cls, pos):
        Pathfinder.move_to(pos, ban_target_pos=True)

        if Pathfinder.given_up:
            Debug.line(pos, Color.RED)
            Debug.diamond(Color.RED)
            cls.state[pos] = 2
            return

        cand: OrePositionPicker.Candidate = OrePositionPicker.pick_best_candidate(pos)
        if cand == None:
            Debug.line(pos, Color.RED)
            Debug.diamond(Color.RED)
            cls.state[pos] = 2
            return
        ti = Map.tile_info[cand.position.x][cand.position.y]
        if ti.entity_type in Constants.TRANSPORTERS_SET:
            cls.state[pos] = 2
            Debug.line(pos, Color.RED)
            Debug.diamond(Color.RED)
            return

        RouteToFoundry.from_pos = pos
        RouteToFoundry.try_claim_target()
        foundry_enc = RouteToFoundry._foundry_target
        if foundry_enc is None or not RouteToFoundry.axionite_can_reach_foundry(cand.position, foundry_enc):
            cls.state[pos] = 2
            Debug.line(pos, Color.RED)
            Debug.diamond(Color.RED)
            RouteToFoundry.give_up(True)
            return
        if BuildManager.can_dbuild_harvester(pos):
            Debug.line(pos, Color.YELLOW)
            BuildManager.dbuild_harvester(pos)
            #Check if already routed naturally
            for d in Constants.CARDINAL_DIRECTIONS:
                newPos = pos.add(d)
                ti = Map.tile_info[newPos.x][newPos.y]
                if ti is None:  # off-map, ignore
                    continue
                if ti.has_building and ti.is_building_ally and ti.entity_type in Constants.TRANSPORTERS_SET:
                    break  # If already routed ignore
            else:
                RouteToFoundry.set_pos(cand.position)
                return
            RouteToFoundry.give_up(True)
        else:
            RouteToFoundry.give_up(True)


# ============================================================
# OrePositionPicker
# ============================================================

class OrePositionPicker:
    class Candidate(NamedTuple):
        position: Position
        ti: TileInfo | None  # if None, it is outside map
        build_metric: int  # manhattan, but if directly on top, need to ~take a step back~
        is_accessible: bool
        empty: bool

    cand: list[Candidate | None] = [None] * 4

    @classmethod
    def precompute(cls, ore_pos: Position):
        my_pos = Globals.my_pos
        me_x, me_y = my_pos.x, my_pos.y

        x, y = ore_pos.x, ore_pos.y


        nx, ny = x , y -1

        build_metric = max(abs(nx - me_x), abs(ny - me_y)) 
        if build_metric == 0:
            build_metric += 2

        ti = Map.tile_info[nx][ny]

        cls.cand[0] = cls.Candidate(
            Position(nx, ny),
            ti,
            build_metric,
            ti is not None and ti.env != Environment.WALL,
            ti is not None and ti.env == Environment.EMPTY,
        )

        nx, ny = x +1, y 

        build_metric = max(abs(nx - me_x), abs(ny - me_y)) 
        if build_metric == 0:
            build_metric += 2

        ti = Map.tile_info[nx][ny]

        cls.cand[1] = cls.Candidate(
            Position(nx, ny),
            ti,
            build_metric,
            ti is not None and ti.env != Environment.WALL,
            ti is not None and ti.env == Environment.EMPTY,
        )

        nx, ny = x , y +1

        build_metric = max(abs(nx - me_x), abs(ny - me_y)) 
        if build_metric == 0:
            build_metric += 2

        ti = Map.tile_info[nx][ny]

        cls.cand[2] = cls.Candidate(
            Position(nx, ny),
            ti,
            build_metric,
            ti is not None and ti.env != Environment.WALL,
            ti is not None and ti.env == Environment.EMPTY,
        )

        nx, ny = x -1, y 

        build_metric = max(abs(nx - me_x), abs(ny - me_y)) 
        if build_metric == 0:
            build_metric += 2

        ti = Map.tile_info[nx][ny]

        cls.cand[3] = cls.Candidate(
            Position(nx, ny),
            ti,
            build_metric,
            ti is not None and ti.env != Environment.WALL,
            ti is not None and ti.env == Environment.EMPTY,
        )

    @classmethod
    def is_better_than(cls, a: Candidate, b: Candidate) -> bool:
        # prio:
        # 0. not null |
        # 1. on map   | collasped
        # 2. empty
        # 3. no building
        # 4. has ally building AND is road
        # 5. no builder bot
        # 6. build metric
        # 7. arbitrary

        if not a.is_accessible: return False
        if not b.is_accessible: return True

        EMPTY = Environment.EMPTY

        if a.empty and (not b.empty): return True
        if (not a.empty) and b.empty: return False

        if a.ti.has_building and (not b.ti.has_building):
            return False
        if (not a.ti.has_building) and b.ti.has_building:
            return True

        if a.ti.has_building and b.ti.has_building:
            ROAD = EntityType.ROAD
            a_cond = a.ti.is_building_ally and a.ti.entity_type == ROAD
            b_cond = b.ti.is_building_ally and b.ti.entity_type == ROAD

            if a_cond and (not b_cond):
                return True
            if (not a_cond) and b_cond:
                return False

        if a.ti.has_bot and (not b.ti.has_bot):
            return False
        if (not a.ti.has_bot) and b.ti.has_bot:
            return True

        if a.build_metric != b.build_metric:
            return a.build_metric < b.build_metric

        return True  # arbitrary

    @classmethod
    def pick_best_candidate(cls, ore_pos: Position) -> Candidate:
        cls.precompute(ore_pos)

        best = cls.cand[3]
        if cls.is_better_than(cls.cand[2], best):
            best = cls.cand[2]
        if cls.is_better_than(cls.cand[1], best):
            best = cls.cand[1]
        if cls.is_better_than(cls.cand[0], best):
            best = cls.cand[0]

        if not best.is_accessible:
            return None

        return best


# ============================================================
# Pathfinder
# ============================================================

class Pathfinder:
    cur_target = None
    given_up: bool = False
    near_base: bool = False  # hysteresis state: prefer empties over roads when True

    @classmethod
    def reset(cls):
        cls.given_up = False
        cls.near_base = False

    @classmethod
    def move_off(cls):
        best_dir = None
        best_w = 1000000
        d = BfsBureau.bfs20_dist
        idx = Globals.my_idx

        nidx = idx -1
        if MoveManager.can_move(Direction.NORTH) and d[nidx] < best_w:
            best_dir = Direction.NORTH
            best_w = d[nidx]
        nidx = idx +55
        if MoveManager.can_move(Direction.NORTHEAST) and d[nidx] < best_w:
            best_dir = Direction.NORTHEAST
            best_w = d[nidx]
        nidx = idx +56
        if MoveManager.can_move(Direction.EAST) and d[nidx] < best_w:
            best_dir = Direction.EAST
            best_w = d[nidx]
        nidx = idx +57
        if MoveManager.can_move(Direction.SOUTHEAST) and d[nidx] < best_w:
            best_dir = Direction.SOUTHEAST
            best_w = d[nidx]
        nidx = idx +1
        if MoveManager.can_move(Direction.SOUTH) and d[nidx] < best_w:
            best_dir = Direction.SOUTH
            best_w = d[nidx]
        nidx = idx -55
        if MoveManager.can_move(Direction.SOUTHWEST) and d[nidx] < best_w:
            best_dir = Direction.SOUTHWEST
            best_w = d[nidx]
        nidx = idx -56
        if MoveManager.can_move(Direction.WEST) and d[nidx] < best_w:
            best_dir = Direction.WEST
            best_w = d[nidx]
        nidx = idx -57
        if MoveManager.can_move(Direction.NORTHWEST) and d[nidx] < best_w:
            best_dir = Direction.NORTHWEST
            best_w = d[nidx]

        if best_dir is None:
            return False

        MoveManager.move(best_dir)
        return True

    @classmethod
    def move_to(cls, target: Position, ban_target_pos: bool = False, orbit: bool = False):
        if Globals.ct.get_move_cooldown() != 0:
            return

        if target != cls.cur_target:
            cls.reset()
            cls.cur_target = target

        Debug.line(target)
        my_pos = Globals.my_pos
        midx = (((my_pos.x) + 3) * 56 + ((my_pos.y) + 3))


        # ── Hysteresis: switch to road-building mode near base/enemy-base ──
        # Enter near_base when rsq <= 18, exit only when rsq > 25.
        # The dead-band [19..25] prevents flickering at the boundary.
        dsq_to_own_core   = my_pos.distance_squared(Unit.core_pos)
        dsq_to_enemy_core = my_pos.distance_squared(Symmetry.enemy_core_pos) if Symmetry.is_sym_known else 1000000
        dsq_to_nearest_base = min(dsq_to_own_core, dsq_to_enemy_core)

        if dsq_to_nearest_base <= 18:
            cls.near_base = True
        elif dsq_to_nearest_base > 25:
            cls.near_base = False
        # else: in dead-band [19..25], keep previous near_base value

        Profiler.start(f"""BfsBureau.find_route""")
        if cls.near_base:
            dist, dir = BfsBureau.find_route_inv(my_pos, target, ban_target_pos)  # prefer empties → lays roads
        else:
            dist, dir = BfsBureau.find_route(my_pos, target, ban_target_pos)      # prefer roads → uses existing roads
        Profiler.end(f"""BfsBureau.find_route""")

        if orbit and 0 < target.distance_squared(my_pos) <= 2:
            dir = my_pos.direction_to(target).rotate_left()


        if dir is not None:
            dsq = my_pos.distance_squared(target)
            ndsq = my_pos.add(dir).distance_squared(target)
            if (dsq == 1 or dsq == 2) and dsq < ndsq: 
                if BfsBureau.now_weight[midx] <= 3:
                    if not MoveManager.can_fill_move(my_pos.direction_to(target)):
                        return

        if dir is None:
            cls.given_up = True
            return

        if MoveManager.can_move(dir):
            MoveManager.move(dir)
        elif MoveManager.can_fill_move(dir):
            Globals.ct.build_road(my_pos.add(dir))
            MoveManager.move(dir)


# ============================================================
# PatrolTargeter
# ============================================================

class PatrolTargeter:
    target: Position
    target = None
    recentHits: set[int] = set()
    lastHitRound: int = 0

    @classmethod
    def init(cls) -> None:
        cls.target = cls.new_target()
        
    @classmethod
    def new_target(cls) -> Position:
        if Globals.my_pos.distance_squared(Unit.core_pos) > 50:
            return Unit.core_pos

        if Map.harvester_set:
            # Check which targets we haven't visited recently
            active_targets = Map.harvester_set.difference(cls.recentHits)
            
            # If there are no active targets, we'll either wait, or if it's been a while since our last hit, reset
            if not active_targets:
                # If it's been a while since we hit the last target, reset our visited set and consider all targets again
                if Globals.round - cls.lastHitRound > 10:
                    cls.recentHits.clear()
                    active_targets = Map.harvester_set
                    
                return None
            else:
                # Choose a random one of the targets we haven't visited recently
                i = random.choice(list(active_targets))
                x, y = ((i) // 56 - 3), ((i) % 56 - 3)
                ti = Map.tile_info[x][y]
                if ti.is_building_ally:
                    return Position(x, y)

        return None

    @classmethod
    def get_best_target(cls) -> Position | None:
        if not Map.harvester_set:
            return None
        
        if BuildManager.can_afford_harvester():
            return None
        
        if cls.target is None:
            cls.target = cls.new_target()
        else:
            if (Globals.my_pos.distance_squared(cls.target) <= 2) or (Pathfinder.cur_target == cls.target and Pathfinder.given_up):
                # Add the position to our set of recently visited targets
                cls.recentHits.add((((cls.target.x) + 3) * 56 + ((cls.target.y) + 3)))
                cls.lastHitRound = Globals.round
                
                cls.target = cls.new_target()
                
        return cls.target


