class Player:
    def run(self, ct):
        try:
            Entrypoint.run(ct)
        except NotImplementedError:
            pass
        except Exception as e:
            Debug.line(Position(0, 0), Color.RED)

            err = traceback.format_exc()
            Debug.tee(err)
            Debug.tee(f'(I am a {Globals.my_type})')

            ct.resign()


