# ============================================================
# RouteToBreach
# ============================================================

class RouteToBreach:
    is_active: bool = False
    from_pos: Position
    killed: set[Position] = set()
    prevRoute = []

    # Positions that have been claimed (or built) as breach sites.
    # Class-level so all bots in this process see the same table.
    planned_breach_positions: set[int] = set()

    # The specific titanium leaf this bot is routing toward.
    # None until a target is claimed in try_build_route.
    _breach_target: int | None = None

    @classmethod
    def _pick_target(cls) -> int | None:
        if not Symmetry.is_sym_known:
            return None
        enemy_core = Symmetry.enemy_core_pos
        print("Yo so the enemy core is at", enemy_core)

        vision_r = int(GameConstants.BREACH_ATTACK_RADIUS_SQ ** 0.5) + 1

        # ── Step 1: pick best attack/sentinel landing position ────────────────
        attack_pos = None
        best_attack_dist = float('inf')
        currLoc = Globals.my_pos
        for dx in range(-vision_r, vision_r + 1):
            for dy in range(-vision_r, vision_r + 1):
                if dx * dx + dy * dy > GameConstants.BREACH_ATTACK_RADIUS_SQ:
                    continue
                candidate = Position(enemy_core.x + dx, enemy_core.y + dy)
                tile = Map.tile_info[candidate.x][candidate.y]
                if tile is None:
                    continue
                if tile.env in [Environment.WALL]:
                    continue
                if tile.has_building and (not tile.is_building_ally):
                    continue
                if tile.has_building and tile.entity_type in Constants.TURRET_SET:
                    continue
                d = currLoc.distance_squared(candidate)
                if d < best_attack_dist:
                    best_attack_dist = d
                    attack_pos = candidate

        if attack_pos is None:
            print("[RouteToBreach] No valid attack position within breach attack of enemy core")
            return None
        print("CLEARLY the best attack position is", attack_pos)
        return (((attack_pos.x) + 3) * 56 + ((attack_pos.y) + 3))
        

    @classmethod
    def set_pos(cls, pos: Position, fullReset = True):
        encoded = (((pos.x) + 3) * 56 + ((pos.y) + 3))

        # Arrived at the breach site — deactivate so the caller can build.
        # Keep the entry in planned_breach_positions: the breach is here now.
        if cls._breach_target is not None and encoded == cls._breach_target:
            cls.is_active = False
            cls.prevRoute.clear()
            return

        if fullReset:
            cls.prevRoute.clear()
        else:
            cls.prevRoute.append(cls.from_pos)
        cls.is_active = True
        cls.from_pos = pos

    @classmethod
    def try_build_route(cls):
        assert cls.is_active

        target_set = {cls._breach_target}

        bridge_dist, first_target = BfsBureau.find_bridge_route_avoid_ti_adj(
            cls.from_pos,
            target_set,
            avoid_pos = RouteToCore.pathFindingKill
        )

        print(f"""{bridge_dist=}""")

        if first_target is None:
            Debug.tee("RouteToBreach: first_target is None, giving up")
            if cls.give_up():
                StateMoveTo.run(Explore.get_target())
            return

        target = Position(*first_target)
        Debug.diline(cls.from_pos, target, Color.GREEN)

        if cls.from_pos.distance_squared(target) == 1:
            if BuildManager.can_dbuild_conveyor(cls.from_pos):
                BuildManager.dbuild_conveyor(cls.from_pos, cls.from_pos.direction_to(target))
                cls.set_pos(target,False)
        elif BuildManager.can_dbuild_bridge(cls.from_pos):
            BuildManager.dbuild_bridge(cls.from_pos, target)
            cls.set_pos(target,False)

    @classmethod
    def move_to_next(cls):
        Pathfinder.move_to(cls.from_pos, ban_target_pos=True)

    @classmethod
    def should_give_up(cls):
        x, y = cls.from_pos
        ti = Map.tile_info[x][y]
        if ti is None:
            return False
        if Pathfinder.given_up:
            return True

        if ti.env in [Environment.WALL]:
            newTarg = cls._pick_target()
            if newTarg is None:
                return True
            else:
                cls._breach_target = newTarg
                return False

        if ti.has_building:
            if not ti.is_building_ally:
                return True
                     
            if ti.entity_type in Constants.TURRET_SET:
                return True
            """
            if cls._breach_target != (((x) + 3) * 56 + ((y) + 3)):
                if ti.entity_type in Constants.TRANSPORTERS_SET:
                    return True
                if ti.entity_type != EntityType.ROAD:
                    return True
            """
        x, y = ((cls._breach_target) // 56 - 3), ((cls._breach_target) % 56 - 3)
        ti = Map.tile_info[x][y]
        if ti is None:
            return False
        if ti.has_building:
            if not ti.is_building_ally:
                newTarg = cls._pick_target()
                if newTarg is None:
                    return True
                else:
                    cls._breach_target = newTarg
                    return False
            if ti.entity_type in Constants.TURRET_SET:
                return True
        return False

    @classmethod
    def give_up(cls):
        if len(cls.prevRoute) == 0: # cooked:
            cls.is_active = False
            # Release the claim so another bot (or a retry) can use this leaf.
            cls.killed.add(cls.from_pos)
            if cls._breach_target is not None:
                cls.planned_breach_positions.discard(cls._breach_target)
                cls._breach_target = None
            if Pathfinder.given_up:
                RouteToCore.pathFindingKill.add((((cls.from_pos.x) + 3) * 56 + ((cls.from_pos.y) + 3)))
            Debug.diamond(Color.PURPLE)
            return True
        else:
            cls.killed.add(cls.from_pos)
            cls.is_active = False
            newPos = cls.prevRoute.pop()
            cls._breach_target = (((newPos.x) + 3) * 56 + ((newPos.y) + 3))
            cls.prevRoute.clear()
            return True

    @classmethod
    def try_claim_target(cls):
        cls._breach_target = cls._pick_target()
        if cls._breach_target is None:
            Debug.tee("RouteToBreach: no possible breach targets, giving up")
            if cls.give_up():
                StateMoveTo.run(Explore.get_target())
            return
        cls.planned_breach_positions.add(cls._breach_target)

    @classmethod
    def do_routing(cls):
        cls.try_claim_target()
        
        if cls._breach_target is None:
            RouteToBreach.is_active = False
            return
        print("Aiming at breach:",((cls._breach_target) // 56 - 3), ((cls._breach_target) % 56 - 3))
        if cls.should_give_up():
            if cls.give_up():
                StateMoveTo.run(Explore.get_target())
            return

        dsq = Globals.my_pos.distance_squared(cls.from_pos)
        if Globals.ct.get_action_cooldown() == 0 \
                and (dsq == 1 or dsq == 2):
            cls.try_build_route()
            cls.move_to_next()
            # if Globals.ct.can_build_road(cls.from_pos):
            #     Globals.ct.build_road(cls.from_pos)
        else:
            cls.move_to_next()


# ============================================================
# RouteToCore
# ============================================================

class RouteToCore:
    is_active: bool = False
    from_pos: Position
    killed: set[Position] = set()
    prevRoute = []
    backTracking = False
    pathFindingKill: set[int] = set()
    isAttack = False

    @classmethod
    def set_pos(cls, pos: Position, fullReset = True):
        if (((pos.x) + 3) * 56 + ((pos.y) + 3)) in DarkForest.core_sink_set:  # was sink_set
            cls.is_active = False
            cls.prevRoute.clear()
            cls.backTracking = False
            return

        if fullReset:
            cls.prevRoute.clear()
            cls.backTracking = False 
        else:
            cls.prevRoute.append(cls.from_pos)
            cls.backTracking = False # Added here to clear backtracking once we resume forward progress
        cls.is_active = True
        cls.from_pos = pos


    @classmethod
    def try_build_route(cls):
        assert cls.is_active
        bridge_dist = 0
        first_target = None
        if cls.isAttack:
            coolPos = RushTargeter.enemy_core_turret_target(GameConstants.SENTINEL_VISION_RADIUS_SQ)
            if coolPos == None:
                cls.give_up(True)
                StateMoveTo.run(Explore.get_target()) # new
            valid_pos_set = set([coolPos]) 
            bridge_dist, first_target = BfsBureau.find_bridge_route(
                cls.from_pos,
                valid_pos_set,
                avoid_pos = cls.pathFindingKill
            )
        else:
            # short search to core in case it's close
            bridge_dist, first_target = BfsBureau.find_bridge_route(
                cls.from_pos,
                Unit.core_pos_set,
                max_iter=0,
                avoid_pos = cls.pathFindingKill
            )
            # otherwise allow all sinks
            if first_target is None:
                bridge_dist, first_target = BfsBureau.find_bridge_route(
                    cls.from_pos,
                    DarkForest.core_sink_set,  # was sink_set
                    avoid_pos = cls.pathFindingKill
                )

        print(f"""{bridge_dist=}""")

        if first_target is None:
            Debug.tee("first_target is None: giving up")
            if cls.give_up(True):
                StateMoveTo.run(Explore.get_target()) # new
            return

        target = Position(*first_target)
        Debug.diline(cls.from_pos, target, Color.GREEN)

        if cls.from_pos.distance_squared(target) == 1:
            if BuildManager.can_dbuild_conveyor(cls.from_pos):
                if BuildManager.should_build_armoured(cls.from_pos) and BuildManager.can_dbuild_armoured_conveyor(cls.from_pos):
                    BuildManager.dbuild_armoured_conveyor(cls.from_pos, cls.from_pos.direction_to(target))
                else:
                    BuildManager.dbuild_conveyor(cls.from_pos, cls.from_pos.direction_to(target))
                cls.set_pos(target,False)

        elif BuildManager.can_dbuild_bridge(cls.from_pos):
            BuildManager.dbuild_bridge(cls.from_pos, target)
            cls.set_pos(target,False)

    @classmethod
    def move_to_next(cls):
        from_pos = cls.from_pos
        Pathfinder.move_to(from_pos, ban_target_pos=True)

        # x, y = from_pos.x, from_pos.y
        # if Map.tile_info[x][y].entity_type == EntityType.ROAD:
        #     Pathfinder.move_to(from_pos, ban_target_pos=False)
        # else:
        #     Pathfinder.move_to(from_pos, ban_target_pos=True)


    @classmethod
    def should_give_up(cls):
        x, y = cls.from_pos
        ti = Map.tile_info[x][y]
        if ti is None:
            return False
        if not cls.backTracking and Pathfinder.given_up:
            return True

        if ti.has_building:
            if not ti.is_building_ally:
                return True
            if not cls.backTracking:
                if ti.entity_type in Constants.TRANSPORTERS_SET:
                    # Another bot already built here — they've taken over, bow out cleanly
                    if ti.target is not None:
                        tx, ty = ti.target.x, ti.target.y
                        if Map.tile_info[tx][ty].entity_type == EntityType.HARVESTER:
                            return False  # it is a shield

                    cls.is_active = False
                    cls.prevRoute.clear()
                    return True
                if ti.entity_type != EntityType.ROAD:
                    return True
        return False


    @classmethod
    def give_up(cls, hard = False):
        from_pos = cls.from_pos
        enc = (((from_pos.x) + 3) * 56 + ((from_pos.y) + 3))
        if hard or len(cls.prevRoute) == 0 or DarkForest.node_kind[enc] in \
                (3, 1):
            cls.is_active = False
            cls.killed.add(from_pos)
            Debug.diamond(Color.PURPLE)
            print("RouteToCore: giving up, no previous route to backtrack to or finished")
            if Pathfinder.given_up:
                cls.pathFindingKill.add(enc)
            cls.backTracking = False
            return True
        else:
            cls.killed.add(from_pos)
            if Pathfinder.given_up:
                cls.pathFindingKill.add(enc)
            from_pos = cls.prevRoute.pop()
            print("RouteToCore: backtracking to", cls.from_pos)
            cls.backTracking = True
            return False


    @classmethod
    def do_routing(cls):
        print("RouteToCore: doing routing from", cls.from_pos,"Attack route",cls.isAttack)
        if cls.should_give_up():
            if cls.give_up():
                StateMoveTo.run(Explore.get_target()) # new
            return

        dsq = Globals.my_pos.distance_squared(cls.from_pos)
        if Globals.ct.get_action_cooldown() == 0 \
                and (dsq <= 2):

            cls.try_build_route()
            cls.move_to_next()
            # if Globals.ct.can_build_road(cls.from_pos):
            #     Globals.ct.build_road(cls.from_pos)
        else:
            cls.move_to_next()


# ============================================================
# RouteToFoundry
# ============================================================

class RouteToFoundry:
    is_active: bool = False
    from_pos: Position
    killed: set[Position] = set()
    prevRoute = []
    backTracking = False

    # Positions that have been claimed (or built) as foundry sites.
    planned_foundry_positions: set[int] = set()

    # The specific titanium leaf this bot is routing toward.
    # None until a target is claimed in try_build_route.
    _foundry_target: int | None = None

    @classmethod
    def axionite_can_reach_foundry(cls, ore_pos: Position, foundry_encoded: int) -> bool:
        """
        Quick reachability check: can we bridge-route from an axionite ore
        position to a specific foundry site?

        Returns False if BfsBureau finds no path, so the caller can reject
        this (ore, foundry) pairing before any routing work begins.
        """
        target_set = {foundry_encoded}

        _, first = BfsBureau.find_bridge_route_avoid_ti_adj(
            ore_pos, 
            target_set, 
            avoid_pos = RouteToCore.pathFindingKill 
        )
        if first is not None:
            return True

        return first is not None

    @classmethod
    def _pick_target(cls) -> int | None:
        """
        Return the encoded position of the closest unclaimed titanium leaf,
        or None if none exist.

        Uses Manhattan distance as a cheap heuristic — good enough given that
        bridge routing later handles the actual terrain.
        """
        candidates = DarkForest.leaf_set - cls.planned_foundry_positions
        if not candidates:
            return None

        nodes = DarkForest.nodes
        bad_sinks = set()
        
        # Identify sinks that already have a foundry planned or built
        for p in cls.planned_foundry_positions:
            curr = p
            # while nodes[curr] is not None and nodes[curr].up is not None:
            #     curr = nodes[curr].up
            for _ in range(3136):
                if nodes[curr] is None or nodes[curr].up is None:
                    break
                curr = nodes[curr].up

            if nodes[curr] is not None:
                bad_sinks.add(curr)

        sx, sy = cls.from_pos.x, cls.from_pos.y
        best: int | None = None
        best_d = 1000000
        for c in candidates:
            # Trace the candidate up to its sink
            curr = c
            # while nodes[curr] is not None and nodes[curr].up is not None:
            #     curr = nodes[curr].up
            for _ in range(3136):
                if nodes[curr] is None or nodes[curr].up is None:
                    break
                curr = nodes[curr].up

            
            # Avoid picking targets if the sink it is in already has a foundry
            if nodes[curr] is not None and curr in bad_sinks:
                continue

            cx = c // 56 - 3
            cy = c % 56 - 3
            ti = Map.tile_info[cx][cy]
            if ti is None:
                continue
            if ti is not None and ti.entity_type == EntityType.BRIDGE:
                continue # do not consider bridges.
            
            d = abs(cx - sx) + abs(cy - sy)

            print(f"RouteToFoundry: candidate {c} at ({cx}, {cy}) has d={d}")
            if d < best_d:
                best_d = d
                best = c
                
        return best

    @classmethod
    def set_pos(cls, pos: Position, fullReset = True):
        encoded = (((pos.x) + 3) * 56 + ((pos.y) + 3))

        # Arrived at the foundry site — deactivate so the caller can build.
        if cls._foundry_target is not None and encoded == cls._foundry_target:
            cls.is_active = False
            cls.prevRoute.clear()
            cls.backTracking = False
            return

        if fullReset:
            cls.prevRoute.clear()
            cls.backTracking = False 
        else:
            cls.prevRoute.append(cls.from_pos)
            cls.backTracking = False # Added here to clear backtracking once we resume forward progress
        cls.is_active = True
        cls.from_pos = pos

    @classmethod
    def try_build_route(cls):
        assert cls.is_active

        target_set = {cls._foundry_target}

        bridge_dist, first_target = BfsBureau.find_bridge_route_avoid_ti_adj(
            cls.from_pos,
            target_set,
            avoid_pos = RouteToCore.pathFindingKill 
        )

        print(f"""{bridge_dist=}""")

        if first_target is None:
            Debug.tee("RouteToFoundry: first_target is None, giving up")
            if cls.give_up():
                StateMoveTo.run(Explore.get_target())
            return

        target = Position(*first_target)
        Debug.diline(cls.from_pos, target, Color.GREEN)

        if cls.from_pos.distance_squared(target) == 1:
            if BuildManager.can_dbuild_conveyor(cls.from_pos):
                BuildManager.dbuild_conveyor(cls.from_pos, cls.from_pos.direction_to(target))
                cls.set_pos(target,False)
        elif BuildManager.can_dbuild_bridge(cls.from_pos):
            BuildManager.dbuild_bridge(cls.from_pos, target)
            cls.set_pos(target,False)

    @classmethod
    def move_to_next(cls):
        Pathfinder.move_to(cls.from_pos, ban_target_pos=True)

    @classmethod
    def should_give_up(cls):
        x, y = cls.from_pos
        ti = Map.tile_info[x][y]
        if ti is None:
            return False
        if not cls.backTracking and Pathfinder.given_up:
            return True

        if ti.has_building:
            if not ti.is_building_ally:
                return True
            if ti.entity_type == EntityType.BRIDGE: #just avoid building foundry on top of a bridge, since that would be sad (too much logic an thinking required)
                    return True
            if not cls.backTracking:
                if cls._foundry_target != (((x) + 3) * 56 + ((y) + 3)):
                    if ti.entity_type in Constants.TRANSPORTERS_SET:
                        return True
                    if ti.entity_type != EntityType.ROAD:
                        return True
            
        return False

    @classmethod
    def give_up(cls, testRun = False):
        if testRun:
            cls.is_active = False
            if cls._foundry_target is not None:
                cls.planned_foundry_positions.discard(cls._foundry_target)
                cls._foundry_target = None
            return False
        if len(cls.prevRoute) == 0:
            cls.is_active = False
            # Release the claim so another bot (or a retry) can use this leaf.
            if cls._foundry_target is not None:
                cls.planned_foundry_positions.discard(cls._foundry_target)
                cls._foundry_target = None
            cls.killed.add(cls.from_pos)
            if Pathfinder.given_up:
                RouteToCore.pathFindingKill.add((((cls.from_pos.x) + 3) * 56 + ((cls.from_pos.y) + 3)))
            Debug.diamond(Color.PURPLE)
            print("RouteToFoundry: giving up from", cls.from_pos)
            cls.backTracking = False
            return True
        else:
            cls.killed.add(cls.from_pos)
            if Pathfinder.given_up:
                RouteToCore.pathFindingKill.add((((cls.from_pos.x) + 3) * 56 + ((cls.from_pos.y) + 3)))
            cls.from_pos = cls.prevRoute.pop()
            print("RouteToFoundry: backtracking to", cls.from_pos)
            cls.backTracking = True
            return False

    @classmethod
    def try_claim_target(cls):
        if cls._foundry_target in cls.planned_foundry_positions:
            cls._foundry_target = cls._pick_target()
            if cls._foundry_target is None:
                Debug.tee("RouteToFoundry: Old leaf used, no unclaimed titanium leaf available")
                if cls.give_up():
                    StateMoveTo.run(Explore.get_target())
            return
        if cls._foundry_target is None: # Claim a target on first call (or if we lost one).
            cls._foundry_target = cls._pick_target()
            if cls._foundry_target is None:
                Debug.tee("RouteToFoundry: no unclaimed titanium leaf available")
                if cls.give_up():
                    StateMoveTo.run(Explore.get_target())
                return
            #cls.planned_foundry_positions.add(cls._foundry_target)
    @classmethod
    def do_routing(cls):
        cls.try_claim_target()
        if cls._foundry_target is None:
            RouteToFoundry.is_active = False
            return
        print("Aiming at foundry:",((cls._foundry_target) // 56 - 3), ((cls._foundry_target) % 56 - 3))
        if cls.should_give_up():
            if cls.give_up():
                StateMoveTo.run(Explore.get_target())
            return

        dsq = Globals.my_pos.distance_squared(cls.from_pos)
        if Globals.ct.get_action_cooldown() == 0 \
                and (dsq == 1 or dsq == 2):
            cls.try_build_route()
            cls.move_to_next()
            # if Globals.ct.can_build_road(cls.from_pos):
            #     Globals.ct.build_road(cls.from_pos)
        else:
            cls.move_to_next()


