class SitterTakedown:
    cand: list[SitterTargetInfo] # adjacent candidate build positions


    @classmethod
    def get_best_launcher_position(cls) -> Position | None:
        if not BuildManager.can_afford_launcher():
            return None
        
        if not cls.cand:
            return None

        best = cls.cand[0]
        for c in cls.cand[1:]:
            if SitterTargetInfo.is_better_than(c, best):
                best = c

        if not best.flowing_enemy_transporters_adjacent:
            if best.enemy_bots_nearby < 2:
                return None
            
            if not best.harvester_nearby:
                return None
            
            if best.enemy_buildings_adjacent == 0:
                return None
            
            return None
        else:
            if best.enemy_bots_nearby == 0:
                return None
        
        if best.launchers_adjacent > 0:
            return None

        if best.bfs_dist_adj >= 100:
            return None

        if not VisionTracker.me_is_canonical_ally(best.position) and best.position.distance_squared(Globals.my_pos) > 2: # Make sure we're a canonical ally *if we're not already adjacent*
            return None

        return best.position


    @classmethod
    def fill(cls):
        cls.cand = []
        tile_info = Map.tile_info

        for pos, x, y, idx, ti in Map.inner_proc_nearby_tiles:
            if ti.env == Environment.WALL:
                continue
            
            if ti.has_bot:
                continue
            
            if ti.has_building:
                if not ti.is_building_ally:
                    continue
                if ti.entity_type != EntityType.ROAD:
                    continue

            if Builder.is_routing_active and pos == Builder.route_from_pos:
                continue

            info = SitterTargetInfo()
            cls.cand.append(info)
            info.position = pos
            info.dist_enemy_core = Util.dist_sq(pos, Symmetry.enemy_core_pos)
            info.enemy_bots_nearby = 0
            info.enemy_buildings_adjacent = 0
            info.harvester_nearby = False
            info.launchers_adjacent = 0
            info.bfs_dist_adj = BfsBureau.bfs20_dist_adj[idx]
