# ============================================================
# SitterTargetInfo
# ============================================================

class SitterTargetInfo:
    __slots__ = (
        'position', 'dist_enemy_core', 'has_ally_transporter',
        'enemy_bots_nearby', 'harvester_nearby', 'launchers_adjacent',
        'bfs_dist_adj', 'flowing_enemy_transporters_adjacent', 'enemy_buildings_adjacent'
    )

    @staticmethod
    def is_better_than(a: SitterTargetInfo, b: SitterTargetInfo):
        if a.bfs_dist_adj >= 100: return False
        if b.bfs_dist_adj >= 100: return True

        if a.launchers_adjacent != b.launchers_adjacent:
            return a.launchers_adjacent < b.launchers_adjacent
        
        if bool(a.flowing_enemy_transporters_adjacent) != bool(b.flowing_enemy_transporters_adjacent):
            return bool(a.flowing_enemy_transporters_adjacent)
        
        # if bool(a.enemy_bots_nearby) != bool(b.enemy_bots_nearby):
        #     return bool(a.enemy_bots_nearby)
        
        if a.enemy_bots_nearby != b.enemy_bots_nearby:
            return a.enemy_bots_nearby > b.enemy_bots_nearby
        
        if a.harvester_nearby != b.harvester_nearby:
            if a.enemy_bots_nearby < 2:
                return a.harvester_nearby < b.harvester_nearby
            else:
                return a.harvester_nearby > b.harvester_nearby
        
        if a.has_ally_transporter != b.has_ally_transporter:
            return a.has_ally_transporter < b.has_ally_transporter
        
        if a.flowing_enemy_transporters_adjacent != b.flowing_enemy_transporters_adjacent:
            return a.flowing_enemy_transporters_adjacent > b.flowing_enemy_transporters_adjacent
        
        if a.enemy_buildings_adjacent != b.enemy_buildings_adjacent:
            return a.enemy_buildings_adjacent < b.enemy_buildings_adjacent

        if a.bfs_dist_adj != b.bfs_dist_adj:
            return a.bfs_dist_adj < b.bfs_dist_adj
        
        return a.dist_enemy_core < b.dist_enemy_core


# ============================================================
# SpawnManager
# ============================================================

class SpawnManager:
    nearest_dangerous_enemy: Position | None
    dangerous_enemy_counter: int = 0

    # persistent
    num_spawned: int = 0


    @classmethod
    def fill(cls):
        my_pos = Globals.my_pos
        dist = 1000000
        enemy = None

        for pos, x, y, idx, ti in Map.proc_nearby_tiles:
            ti: TileInfo

            if not ti.entity_type in Constants.ATTACKABLE_TRANSPORTERS_SET:
                continue
            if not (ti.has_bot and not ti.is_bot_ally):
                continue
            if ti.allied_bots_adjacent > 0:
                continue

            # Calculate the distance first
            d = my_pos.distance_squared(pos)

            if enemy is None or d < dist:
                dist = d
                enemy = pos

        cls.nearest_dangerous_enemy = enemy
        
        if cls.nearest_dangerous_enemy != None:
            cls.dangerous_enemy_counter += 1
        else:
            cls.dangerous_enemy_counter = 0




    @classmethod
    def spawn(cls):
        # rework this
        my_pos = Globals.my_pos

        pos = my_pos.add(Direction.CENTRE)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.NORTHWEST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.WEST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.SOUTHWEST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.SOUTH)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.SOUTHEAST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.EAST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.NORTHEAST)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1
        pos = my_pos.add(Direction.NORTH)
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1


    @classmethod
    def should_spawn(cls):
        ct = Globals.ct
        num_units = ct.get_unit_count()

        ti, ax = ct.get_global_resources()
        bot_ti, bot_ax = ct.get_builder_bot_cost()

        if Globals.round <= 10 and cls.num_spawned < 5:
            return True

        mass = 80 if cls.num_spawned < 10 else 200

        if ti - bot_ti >= num_units * mass:
            return True

        return False


    @classmethod
    def should_spawn_emergency(cls):
        if cls.dangerous_enemy_counter >= 3: # Only spawn emergency if there's been a dangerous enemy for 3 or more rounds in a row
            return True
        
        lost_short = CoreHistory.hp_delta(1) < 0 
        lost_long = CoreHistory.hp_delta(10) < 0 
        low_hp = Globals.ct.get_hp() < 450

        if (lost_short or lost_long) and low_hp:
            return True

        return False


# ============================================================
# StalkTargeter
# ============================================================

class StalkTargeter:
    @classmethod
    def get_best_target(cls) -> Position | None:
        Profiler.start(f"""StalkTargeter.get_best_target""")

        my_pos = Globals.my_pos

        if my_pos.distance_squared(Unit.core_pos) > my_pos.distance_squared(Symmetry.enemy_core_pos):
            Profiler.end(f"""pop""")
            return None

        if MarketMaker.est_income < 3:
            Profiler.end(f"""pop""")
            return None

        bfs20_dist_adj = BfsBureau.bfs20_dist_adj
        
        best: Position = None
        best_dist: int = 1000000

        for pos, x, y, idx, ti in Map.proc_nearby_tiles:

            if ti.has_bot and not ti.is_bot_ally \
                    and VisionTracker.me_is_canonical_ally(pos):
                dist = bfs20_dist_adj[idx]
                if dist < best_dist:
                    best_dist = dist
                    best = pos
                
        Profiler.end(f"""StalkTargeter.get_best_target""")
                
        return best


