        'env', 'round', 'easily_passable', 'harvester_adjacent',
        'has_building', 'building_hp', 'building_id', 'is_building_ally',
        'entity_type', 'target',
        'has_bot', 'bot_hp', 'bot_id', 'is_bot_ally',
        'allied_bots_adjacent',
        'has_turret', 'turret_direction',
