# ============================================================
# TurretSuicide
# ============================================================

class TurretSuicide:
    has_ammo_history: list[bool]
    enemy_core_visible: bool
    post_init_completed: bool
    

    @classmethod
    def init(cls):
        cls.has_ammo_history = [True] * 20
        cls.enemy_core_visible = False
        cls.post_init_completed = False


    @classmethod
    def post_init(cls):
        # hack
        for pos, x, y, idx, ti in Map.proc_nearby_tiles:
            ti: TileInfo
            if ti.entity_type == EntityType.CORE and not ti.is_building_ally:
                cls.enemy_core_visible = True
                break
        cls.post_init_completed = True


    @classmethod
    def update_and_check(cls):
        if not cls.post_init_completed:
            cls.post_init()

        my_pos = Globals.my_pos
        sx, sy = my_pos.x, my_pos.y

        r = Globals.round % 20
        cls.has_ammo_history[r] = Globals.ct.get_ammo_amount() > 0

        has_feeder = Map.tile_info[sx][sy].harvester_adjacent
        for pos, x, y, idx, ti in Map.proc_nearby_tiles:
            ti: TileInfo
            if ti.target == my_pos:
                has_feeder = True
                break

        if not has_feeder and not cls.enemy_core_visible and not any(cls.has_ammo_history):
            Debug.diamond(Color.ORANGE)
            Debug.log(f'This {Globals.my_type} is self-destructing :(')
            Globals.ct.self_destruct()


# ============================================================
# Unit
# ============================================================

class Unit:

    core_pos: Position
    core_pos_list: list[tuple[int, int]]
    core_pos_set: set[int]

    on_pong: bool = False

    @staticmethod
    def core_pos_init():
        core_id = Globals.ct.get_tile_building_id(Globals.my_pos)
        Unit.core_pos = Globals.ct.get_position(core_id)
        x = Unit.core_pos.x
        y = Unit.core_pos.y
        Unit.core_pos_list = [
            (x , y -1),
            (x +1, y -1),
            (x +1, y ),
            (x +1, y +1),
            (x , y +1),
            (x -1, y +1),
            (x -1, y ),
            (x -1, y -1),
            (x , y ),
        ]
        idx = (((x) + 3) * 56 + ((y) + 3))
        Unit.core_pos_set = {
            idx -1,
            idx +55,
            idx +56,
            idx +57,
            idx +1,
            idx -55,
            idx -56,
            idx -57,
            idx ,
        }


    @classmethod
    def init(cls):
        random.seed(Globals.my_id)
        BfsBureau.init()

        if Globals.my_type in (EntityType.BUILDER_BOT, EntityType.CORE):
            Unit.core_pos_init()
            Symmetry.predict_enemy_core()
        else:
            cls.core_pos_set = set()

        if Globals.my_type in (EntityType.BUILDER_BOT, EntityType.CORE) and (Map.maxX, Map.maxY) == (49, 34):
            cx, cy = cls.core_pos.x, cls.core_pos.y
            isA = Globals.ct.get_team() == Team.A

            if (isA and (cx, cy) == (8, 8)) or (not isA and (cx, cy) == (41, 8)):
                PongManager.init()
                Debug.log('PONG detected!!')
                cls.on_pong = True


    @classmethod
    def start_turn(cls):
        if cls.on_pong:
            Globals.start_tick()
            PongManager.run()
            raise NotImplementedError

        Globals.start_tick()
        MarketMaker.refresh()

        if Globals.ct.get_entity_type() != EntityType.LAUNCHER:
            Profiler.start(f"""Map.fill_tile_info""")
            Map.fill_tile_info()
            Profiler.end(f"""Map.fill_tile_info""")

        Profiler.start_turn_check()

    @classmethod
    def run_turn(cls):
        pass

    @classmethod
    def end_turn(cls):

        if Globals.round == 667:
            Profiler.report()
        print(f'scale ratio {MarketMaker.scale_ratio:.2f}')


# ============================================================
# Breach
# ============================================================

class Breach(Unit):
    @classmethod
    def init(cls):
        Unit.init()
        DarkForest.init()

    @classmethod
    def start_turn(cls):
        Unit.start_turn()
        DarkForest.fcompute()
        DarkForest.debug_kind()

    @classmethod
    def run_turn(cls):
        ct = Globals.ct
        nearbyTiles = ct.get_nearby_tiles()
        nearbyCore = False
        for tile in nearbyTiles:
            daBuildingID = ct.get_tile_building_id(tile)
            if daBuildingID is not None:
                if ct.get_team(daBuildingID) != Globals.my_team and ct.get_entity_type(daBuildingID) == EntityType.CORE:
                    nearbyCore = True
                    break
        RANGE_DIST = 5
        if nearbyCore:
            RANGE_DIST = 2 #nearby core, shoot closer
        print("Nearby core?", nearbyCore, "Range dist:", RANGE_DIST)
        myDir = Globals.ct.get_direction()
        myPos = Globals.my_pos
        newPos = myPos
        for _ in range(RANGE_DIST):
            newPos =newPos.add(myDir)
        opposite = myDir.opposite()
        for _ in range(RANGE_DIST):
            if Globals.ct.can_fire(newPos):
                Globals.ct.fire(newPos)
                print("Yo firing at", newPos)
                return
            newPos = newPos.add(opposite)
    @classmethod
    def end_turn(cls):
        Unit.end_turn()


# ============================================================
# Builder
# ============================================================

class Builder(Unit):

    state: str
    mode: int = 0
    role: int = 0
    min_dist_to_a_core: int

    is_routing_active: bool = False
    route_from_pos: Position

    should_fire: bool

    @classmethod
    def init(cls):
        Unit.init()
        Explore.init()
        DarkForest.init()
        BfsBureau.enclosed_init()
        cls.state = 'Explore'
        if Globals.round == 5:
            cls.role = 1

    @classmethod
    def start_turn(cls):
        Unit.start_turn()

        my_pos = Globals.my_pos
        cls.min_dist_to_a_core = min(my_pos.distance_squared(Unit.core_pos), my_pos.distance_squared(Symmetry.enemy_core_pos))

        Profiler.start(f"""DarkForest.fcompute""")
        DarkForest.fcompute()
        Profiler.end(f"""DarkForest.fcompute""")

        Profiler.start(f"""BfsBureau.update""")
        BfsBureau.update()
        Profiler.end(f"""BfsBureau.update""")

        Symmetry.run_sym_check()

        if cls.mode == 0:
            if Globals.round in [2,3]:
                cls.mode = 2
                Explore.target = Explore.new_target()
            elif Globals.round in [4]:
                cls.mode = 3
                Explore.target = Explore.new_target()
            else:
                cls.mode = 1
        if Globals.round >= Constants.RUSH_OVER:
            cls.mode = 1
            # Explore.target = Explore.new_target()

        print("Mode:", cls.mode)


        Profiler.start(f"""BfsBureau.bfs20""")
        BfsBureau.bfs20()
        Profiler.end(f"""BfsBureau.bfs20""")

        Profiler.start(f"""BfsBureau.update_enclosed_regions""")
        BfsBureau.update_enclosed_regions()
        Profiler.end(f"""BfsBureau.update_enclosed_regions""")


        Profiler.start(f"""OreExecutive.fill""")
        OreExecutive.fill()
        Profiler.end(f"""OreExecutive.fill""")

        Profiler.start(f"""VisionTracker.fill""")
        VisionTracker.fill()
        Profiler.end(f"""VisionTracker.fill""")

        Profiler.start(f"""SitterTakedown.fill""")
        SitterTakedown.fill()
        Profiler.end(f"""SitterTakedown.fill""")

        Profiler.start(f"""HarvesterAdjacent.fill""")
        HarvesterAdjacent.fill()
        Profiler.end(f"""HarvesterAdjacent.fill""")

        Profiler.start(f"""HealTargeter.fill""")
        HealTargeter.fill()
        Profiler.end(f"""HealTargeter.fill""")

        cls.is_routing_active = False

        if RouteToCore.is_active:
            cls.is_routing_active = True
            cls.route_from_pos = RouteToCore.from_pos
        if RouteToBreach.is_active:
            cls.is_routing_active = True
            cls.route_from_pos = RouteToBreach.from_pos
        if RouteToFoundry.is_active:
            cls.is_routing_active = True
            cls.route_from_pos = RouteToFoundry.from_pos

        cls.should_fire = Attacker.should_fire(Globals.my_pos)



    @classmethod
    def run_turn(cls):
        cls.state, *args = cls.determine_state()

        print(f'running: {cls.state}  @', *args, sep=' ')

        Profiler.start(f"""State{cls.state}""")
        globals()[f'State{cls.state}'].run(*args)
        Profiler.end(f"""State{cls.state}""")


    @classmethod
    def end_turn(cls):
        Unit.end_turn()

        Profiler.start(f"""HealExecutor.execute_heal_attempt""")
        HealExecutor.execute_heal_attempt()
        Profiler.end(f"""HealExecutor.execute_heal_attempt""")

        Profiler.start(f"""Marker.attempt_mark""")
        Marker.attempt_mark()
        Profiler.end(f"""Marker.attempt_mark""")


        # BfsBureau.debug_bfs20_dist_adj()
        # BfsBureau.debug_enemy_launcher_zone()
        # BfsBureau.debug_ally_launcher_zone()

        # if Globals.round & 1:
        #     BfsBureau.debug_now_passable_int_impassable()
        # else:
        #     BfsBureau.debug_now_weight_inf()

        # my_pos = Globals.my_pos
        # if Globals.ct.can_fire(my_pos) and Attacker.should_fire(my_pos) and Map.num_enemies == 0:
        #     Globals.ct.fire(my_pos)
        
        # if Map.num_enemies > 0 or cls.min_dist_to_a_core <= 36:
        if cls.min_dist_to_a_core <= 36:
            RoadspamExecutor.execute_roadspam_attempt()




    @classmethod
    def determine_state(cls):
        my_pos = Globals.my_pos
        ct = Globals.ct

        healinfo = HealTargeter.get_best_target_info()
        healpos = None
        if healinfo is not None:
            if healinfo.entity_type == EntityType.CORE:
                healpos = Unit.core_pos
            else:
                healpos = healinfo.position

        takedowninfo = HarvesterAdjacent.get_best_turret_takedown_info()
        takedownpos = None if takedowninfo is None else takedowninfo.position

        misinfo: TransporterInfo = VisionTracker.get_best_misrouted_target() 

        # now changed to sentinel/gunner pos near enemy?
        sentinelpos = HarvesterAdjacent.get_best_sentinel_position()
        
        if RouteToBreach.is_active:
            return ('RouteBreach',)

        if (
             HealExecutor.last_healed is not None 
             and HealExecutor.last_healed.is_turret
             and (Globals.round - HealExecutor.last_healed_round) <= 5
        ):
            if healpos is not None:  # redundant, OK
                return 'MoveTo', healpos, '[lrh: move to heal]'

        if takedownpos is not None:
            Debug.dot(takedownpos, Color.PURPLE)
            return 'BuildGunner', takedownpos, None

        sitterpos = SitterTakedown.get_best_launcher_position()
        if sitterpos is not None:
            Debug.dot(sitterpos, Color.PURPLE)
            return 'BuildLauncher', sitterpos

        if healpos is not None:
            return 'MoveTo', healpos, 'Heal'


        # reinstating CORE_HEALER
        if cls.role == 1:
            return 'MoveTo', Unit.core_pos.add(random.choice(Constants.DIRECTIONS)), '[core healer]'
            
        buildingFirstConveyor = RouteToCore.is_active and len(RouteToCore.prevRoute) == 0
            
        if not buildingFirstConveyor:
            shieldpos = HarvesterAdjacent.get_best_shield_position()
            if shieldpos is not None:
                return 'BuildShield', shieldpos
                
        attackpos = Attacker.get_target()
        secondaryattackpos = Attacker.get_secondary_target()

        if cls.should_fire:
            return 'Attack', Globals.my_pos, 'ShouldFire'
        
        # preroute here
        if cls.is_routing_active and secondaryattackpos == cls.route_from_pos:
            return 'Attack', secondaryattackpos, 'Preroute'


        if RouteToFoundry.is_active:
            return ('RouteFoundry',)

        if RouteToCore.is_active:
            return ('Route',)

        if misinfo is not None and not ((RouteToCore.backTracking or RouteToFoundry.backTracking) and not RouteToCore.is_active and not RouteToFoundry.is_active):
            if misinfo.on_ally_side:
                return 'Reroute', misinfo.position
            else:
                return 'Reroute', misinfo.position  # same

        trans: TransporterInfo = ConnectManager.get_connect_target_info()
        if trans is not None:
            tpos = trans.target

            if Util.dist_sq(tpos, Symmetry.enemy_core_pos) \
                    < Util.dist_sq(tpos, Unit.core_pos):
                return 'BuildTurret', tpos 

            # if tpos not in RouteToCore.killed:
            if True:
                RouteToCore.set_pos(tpos)
                return 'MoveTo', tpos, 'InitRoute'

        route_pos = HarvesterAdjacent.get_best_route_position()
        if route_pos is not None and cls.mode != 2:
            RouteToCore.set_pos(route_pos)
            if RouteToCore.is_active:
                print("""[HarvesterAdjacent found route]""")
                return ('Route',)


        if sentinelpos is not None:
            Debug.dot(sentinelpos, Color.PURPLE)
            return 'BuildTurret', sentinelpos, None
            
        if buildingFirstConveyor:
            shieldpos = HarvesterAdjacent.get_best_shield_position()
            if shieldpos is not None:
                return 'BuildShield', shieldpos


        breach_target = BreachBuild._pick_target()
        if breach_target is not None:
            return 'BreachBuild', breach_target
        
        foundry_target = FoundryBuild._pick_target()
        if foundry_target is not None:
            return 'FoundryBuild', foundry_target

        
        if attackpos is not None:
            return 'Attack', attackpos, 'Primary'

        if cls.min_dist_to_a_core <= 48:
            if secondaryattackpos is not None:
                if Globals.my_pos.distance_squared(secondaryattackpos) <= 2:
                    return 'Attack', secondaryattackpos, 'Secondary'
                
        ax_target = OreExecutive.get_axionite_target()
        ti_target = OreExecutive.get_titanium_target()
        stalk_target = StalkTargeter.get_best_target()

        dist_ti = 1000000 if ti_target is None else my_pos.distance_squared(ti_target)
        dist_ax = 1000000 if ax_target is None else my_pos.distance_squared(ax_target)
        dist_stalk = 1000000 if stalk_target is None else my_pos.distance_squared(stalk_target)

        if my_pos.distance_squared(Symmetry.enemy_core_pos) > my_pos.distance_squared(Unit.core_pos) or attackpos is None:
            if (dist_stalk <= 4 or (dist_stalk < dist_ti and dist_stalk < dist_ax)) and cls.mode != 2:
                return 'MoveTo', stalk_target, 'Stalk'

        if ax_target is not None and MarketMaker.ax == 0 and cls.mode != 2:
            return 'BuildHarvesterAx', ax_target

        if ti_target is not None and cls.mode != 2:
            return 'BuildHarvester', ti_target

        if ax_target is not None and cls.mode != 2:
            return 'BuildHarvesterAx', ax_target


        if my_pos.distance_squared(Symmetry.enemy_core_pos) > my_pos.distance_squared(Unit.core_pos) or attackpos is None:
            if stalk_target is not None and cls.mode != 2:
                return 'MoveTo', stalk_target, 'Stalk'

        if secondaryattackpos is not None:
            return 'Attack', secondaryattackpos, 'secondary'
            
        rushTarget = RushTargeter.get_best_target()
        if rushTarget is not None:
            return 'Rush', rushTarget

        if ct.get_unit_count() < 15 or Globals.my_id % 3 == 0:
            patrolTarget = PatrolTargeter.get_best_target()
            if patrolTarget is not None:
                return 'MoveTo', patrolTarget, 'Patrol'

        return 'MoveTo', Explore.get_target(), 'Explore'


